import ms2deepscore; import matchms; import numpy as np; import pandas as pd; from rdkit import Chem; model = ms2deepscore.MS2DeepScore.load_pretrained(); spectra = np.load('{inputs.test_spectra}'); metadata = pd.read_csv('{inputs.metadata}'); predictions = []; for i, s1 in enumerate(spectra): 
  for j, s2 in enumerate(spectra[i+1:]): 
    mc_preds = [model.pair(s1, s2) for _ in range(10)]; median_pred = np.median(mc_preds); iqr = np.percentile(mc_preds, 75) - np.percentile(mc_preds, 25); predictions.append({'spectrum_pair_id': f'{i}_{i+j+1}', 'spectrum_1_idx': i, 'spectrum_2_idx': i+j+1, 'predicted_tanimoto': median_pred, 'ground_truth_tanimoto': metadata.iloc[i]['tanimoto_label'], 'prediction_uncertainty_iqr': iqr, 'passed_iqr_filter': iqr < 0.025}); df = pd.DataFrame(predictions); rmse_full = np.sqrt(np.mean((df['predicted_tanimoto'] - df['ground_truth_tanimoto'])**2)); rmse_filtered = np.sqrt(np.mean((df[df['passed_iqr_filter']]['predicted_tanimoto'] - df[df['passed_iqr_filter']]['ground_truth_tanimoto'])**2)); print(f'RMSE (no filter): {rmse_full:.4f}'); print(f'RMSE (IQR < 0.025): {rmse_filtered:.4f}'); df.to_csv('ms2deepscore_predictions.csv', index=False)
